mapper.select:
SELECT COUNT(*)
FROM user
WHERE user_id = #{userId}

mapper.update:
UPDATE user
SET user_no = user_no

    , name = #{name}


    , tel = #{tel}


    , gender = #{gender}


    , birth = #{birth}


    , user_pw = #{userPw}

WHERE user_no = #{userNo}

mapper.select:
SELECT COUNT(*) FROM review r
                         JOIN orders o ON o.order_id = r.order_id
WHERE o.user_no = #{userNo}

mapper.delete:
DELETE r FROM review r
JOIN orders o ON o.order_id = r.order_id
WHERE r.review_id = #{reviewId}
AND o.user_no = #{userNo}

mapper.select:
SELECT o.store_id FROM review r
                           JOIN orders o ON o.order_id = r.order_id
WHERE r.review_id = #{reviewId}

mapper.update:
UPDATE store s
SET s.rating_avg = (
    SELECT IFNULL(ROUND(AVG(r.rating)), 0)
    FROM review r
             JOIN orders o ON o.order_id = r.order_id
    WHERE o.store_id = #{storeId}
),
    s.rating_count = (
        SELECT COUNT(1)
        FROM review r
                 JOIN orders o ON o.order_id = r.order_id
        WHERE o.store_id = #{storeId}
    )
WHERE s.store_id = #{storeId}
